#include<bits/stdc++.h>
using namespace std;
struct node
{
    double x,y;
    bool operator<(const node&b)const
    {
        return(x==b.x?y<b.y:x<b.x);
    }
}a[100010],q[100010];
double dis(node i,node j)
{
    return sqrt(pow(i.x-j.x,2)+pow(i.y-j.y,2));
}
int main()
{
    int tot=0;
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lf%lf",&a[i].x,&a[i].y);
    }
    sort(a+1,a+1+n);
    q[++tot]=a[1];
    for(int i=2;i<=n;i++)
    {
        while(tot>=2&&(a[i].y-q[tot].y)*(q[tot].x-q[tot-1].x)>=(q[tot].y-q[tot-1].y)*(a[i].x-q[tot].x))
        {
            tot--;
        }
        q[++tot]=a[i];
    }
    double ans=0;
    for(int i=1;i<tot;i++)
    {
        ans+=dis(q[i],q[i+1]);
    }
    q[tot=1]=a[n];
    for(int i=n-1;i>=1;i--)
    {
        while(tot>=2&&(a[i].y-q[tot].y)*(q[tot].x-q[tot-1].x)>=(q[tot].y-q[tot-1].y)*(a[i].x-q[tot].x))
        {
            tot--;
        }
        q[++tot]=a[i];
    }
    for(int i=1;i<tot;i++)
    {
        ans+=dis(q[i],q[i+1]);
    }
    printf("%.2lf\n",ans);
    return 0;
}
